 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import { formatTime, formatTimeLastRunTime } from '../dateTime';
 19	import { ALL_NAMESPACES_KEY } from '../../../consts';
 20	import {
 21	  PipelineModel,
 22	  PipelineModelV1Beta1,
 23	  ProjectModel,
 24	} from '../../../models';
 25	import { Project } from '../../../types';
 26	
 27	const PipelineRunsForPipelinesRowK8s: React.FC<
 28	  RowProps<
 29	    SummaryProps,
 30	    {
 31	      hideLastRunTime?: boolean;
 32	      projects: Project[];
 33	      projectsLoaded: boolean;
 34	    }
 35	  >
 36	> = ({ obj, rowData: { hideLastRunTime, projects, projectsLoaded } }) => {
 37	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 38	  const [activeNamespace] = useActiveNamespace();
 39	  const [namespace, name] = obj.group_value.split('/');
 40	  const clusterVersion = (window as any).SERVER_FLAGS?.releaseVersion;
 41	  const isV1SupportCluster =
 42	    clusterVersion?.split('.')[0] === '4' &&
 43	    clusterVersion?.split('.')[1] > '13';
 44	  const pipelineReference = getReferenceForModel(
 45	    isV1SupportCluster ? PipelineModel : PipelineModelV1Beta1,
 46	  );
 47	  const projectReference = getReferenceForModel(ProjectModel);
 48	
 49	  const isNamespaceExists = (namespaceName: string) => {
 50	    if (!projectsLoaded) {
 51	      return false;
 52	    }
 53	    return projects.some(
 54	      (project) =>
 55	        project?.metadata && project?.metadata?.name === namespaceName,
 56	    );
 57	  };
 58	
 59	  return (
 60	    <>
 61	      <td className={tableColumnClasses[0]}>
 62	        {isNamespaceExists(namespace) ? (
 63	          <ResourceLink
 64	            groupVersionKind={
 65	              isV1SupportCluster
 66	                ? getGroupVersionKindForModel(PipelineModel)
 67	                : getGroupVersionKindForModel(PipelineModelV1Beta1)
 68	            }
 69	            name={name}
 70	            namespace={namespace}
 71	          />
 72	        ) : (
 73	          <Tooltip content={t('Resource is deleted.')}>
 74	            <span>
 75	              <ResourceIcon kind={pipelineReference} />
 76	              {name}
 77	            </span>
 78	          </Tooltip>
 79	        )}
 80	      </td>
 81	      {activeNamespace === ALL_NAMESPACES_KEY && (
 82	        <td className={tableColumnClasses[1]}>
 83	          {isNamespaceExists(namespace) ? (
 84	            <ResourceLink kind="Namespace" name={namespace} />
 85	          ) : (
 86	            <Tooltip content={t('Resource is deleted.')}>
 87	              <span>
 88	                <ResourceIcon kind={projectReference} />
 89	                {namespace}
 90	              </span>
 91	            </Tooltip>
 92	          )}
 93	        </td>
 94	      )}
 95	      <td className={tableColumnClasses[2]}>
 96	        {isNamespaceExists(namespace) ? (
 97	          <Link to={`/k8s/ns/${namespace}/${pipelineReference}/${name}/Runs`}>
 98	            {obj.total}
 99	          </Link>
100	        ) : (
101	          <span>{obj.total}</span>
102	        )}
103	      </td>
104	      <td className={tableColumnClasses[3]}>
105	        {formatTime(obj.total_duration)}
106	      </td>
107	      <td className={tableColumnClasses[4]}>{formatTime(obj.avg_duration)}</td>
108	      <td className={tableColumnClasses[5]}>{`${Math.round(
109	        (100 * obj.succeeded) / obj.total,
110	      )}%`}</td>
111	      {!hideLastRunTime && (
112	        <td className={tableColumnClasses[6]}>{`${formatTimeLastRunTime(
113	          obj.last_runtime,
114	        )}`}</td>
115	      )}
116	    </>
117	  );
118	};
119	
120	export default PipelineRunsForPipelinesRowK8s;

